const token = process.env.GHL_PRIVATE_INTEGRATION_TOKEN || process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB || process.env.GHL_TOKEN;
const loc = 'TW8JsPW5NMnA3tfK2XLn';
const h = { Authorization: 'Bearer ' + token, Version: '2021-07-28', Accept: 'application/json', 'Content-Type': 'application/json' };
const base = 'https://services.leadconnectorhq.com';
const now = new Date('2026-03-21T23:38:00Z');
const day = 24 * 60 * 60 * 1000;

async function get(path) {
  const r = await fetch(base + path, { headers: h });
  const t = await r.text();
  let j = {};
  try { j = JSON.parse(t || '{}'); } catch { j = { raw: t }; }
  if (!r.ok) throw new Error(`${r.status} ${path} ${(t || '').slice(0, 180)}`);
  return j;
}

function toMs(v) {
  if (v == null) return null;
  if (typeof v === 'number') return v > 1e12 ? v : v * 1000;
  const m = Date.parse(v);
  return Number.isFinite(m) ? m : null;
}

function cfObj(customFields) {
  const out = {};
  if (Array.isArray(customFields)) {
    for (const f of customFields) {
      const k = f.key || f.fieldKey || f.name || f.id;
      const v = f.value ?? f.fieldValue ?? f.values;
      if (k) out[String(k)] = v;
    }
  } else if (customFields && typeof customFields === 'object') {
    Object.assign(out, customFields);
  }
  return out;
}

(async () => {
  const pipes = (await get(`/opportunities/pipelines?locationId=${loc}`)).pipelines || [];
  const stageMap = {};
  for (const p of pipes) for (const s of (p.stages || [])) stageMap[s.id] = s.name;

  let opps = [];
  for (const p of pipes) {
    const j = await get(`/opportunities/search?location_id=${loc}&pipeline_id=${p.id}&limit=200`);
    opps.push(...(j.opportunities || []));
  }
  opps = opps.filter(o => !['won', 'lost'].includes((o.status || 'open').toLowerCase()));

  const stale = opps
    .map(o => {
      const t = Math.max(toMs(o.updatedAt) || 0, toMs(o.lastStageChangeAt) || 0, toMs(o.lastStatusChangeAt) || 0, toMs(o.createdAt) || 0);
      const days = Math.floor((now - t) / day);
      return { o, days };
    })
    .filter(x => x.days >= 3)
    .sort((a, b) => b.days - a.days);

  const conv = (await get(`/conversations/search?locationId=${loc}&limit=200`)).conversations || [];
  const convByContact = {};
  for (const c of conv) {
    const t = toMs(c.lastMessageDate) || toMs(c.dateUpdated) || toMs(c.dateAdded) || 0;
    if (!convByContact[c.contactId] || t > convByContact[c.contactId]) convByContact[c.contactId] = t;
  }

  const commStale = [];
  const seen = new Set();
  for (const o of opps) {
    const cid = o.contactId;
    if (!cid || seen.has(cid)) continue;
    seen.add(cid);
    const last = convByContact[cid] || 0;
    const days = last ? Math.floor((now - last) / day) : 999;
    if (days >= 7) commStale.push({ o, days });
  }
  commStale.sort((a, b) => b.days - a.days);

  const cals = (await get(`/calendars/?locationId=${loc}`)).calendars || [];
  const start = '2026-03-21T00:00:00-05:00';
  const end = '2026-03-23T00:00:00-05:00';
  const events = [];
  for (const cal of cals) {
    try {
      const j = await get(`/calendars/events?calendarId=${cal.id}&startTime=${encodeURIComponent(start)}&endTime=${encodeURIComponent(end)}`);
      const arr = j.events || j.appointments || j.data || [];
      for (const e of arr) events.push({ ...e, calendarName: cal.name, calendarId: cal.id });
    } catch {}
  }
  const dedup = {};
  for (const e of events) {
    const id = e.id || `${e.calendarId}:${e.startTime || e.start || e.dateAdded}:${e.contactId || e.title}`;
    dedup[id] = e;
  }
  const upcoming = Object.values(dedup).filter(e => {
    const t = toMs(e.startTime || e.start || e.appointmentStartTime || e.dateAdded);
    return t && t >= Date.parse(start) && t < Date.parse(end);
  });

  const missingBrief = [];
  for (const e of upcoming) {
    const cid = e.contactId || e?.contact?.id;
    const opp = opps.find(x => x.contactId === cid);
    const tags = [...(opp?.contact?.tags || []), ...(e?.contact?.tags || [])].map(x => String(x).toLowerCase());
    const hasBrief = tags.some(t => t.includes('brief')) || Boolean(e.briefingSentAt || e.briefing_sent_at || e.preCallBriefing);
    if (!hasBrief) {
      missingBrief.push({
        name: opp?.contact?.name || e.contact?.name || e.title || 'Unknown',
        start: e.startTime || e.start || e.appointmentStartTime || null,
        calendar: e.calendarName,
        contactId: e.contactId || opp?.contactId || null
      });
    }
  }

  const rev = {};
  let total = 0;
  for (const o of opps) {
    const stage = stageMap[o.pipelineStageId] || 'Unknown';
    const val = Number(o.monetaryValue || o.monetary_value || 0) || 0;
    if (!rev[stage]) rev[stage] = { count: 0, value: 0 };
    rev[stage].count++;
    rev[stage].value += val;
    total += val;
  }
  const revenue = Object.entries(rev).map(([stage, v]) => ({ stage, ...v })).sort((a, b) => b.value - a.value);

  const hot = [];
  for (const o of opps) {
    const c = o.contact || {};
    const cfo = cfObj(c.customFields);
    const lead = Number(cfo.lead_score || cfo.leadScore || c.lead_score || c.leadScore || 0) || 0;
    const align = Number(cfo.alignment_score || cfo.alignmentScore || 0) || 0;
    if (lead >= 90 || align >= 90) {
      const last = convByContact[o.contactId] || 0;
      hot.push({ o, lead, align, lastContactDays: last ? Math.floor((now - last) / day) : 999 });
    }
  }
  hot.sort((a, b) => Math.max(b.lead, b.align) - Math.max(a.lead, a.align));

  const out = {
    generatedAt: now.toISOString(),
    counts: { opps: opps.length, stale: stale.length, commStale: commStale.length, events: upcoming.length, missingBrief: missingBrief.length, hot: hot.length },
    stale: stale.slice(0, 15).map(x => ({ name: x.o.contact?.name || x.o.name, stage: stageMap[x.o.pipelineStageId] || 'Unknown', days: x.days })),
    commStale: commStale.slice(0, 15).map(x => ({ name: x.o.contact?.name || x.o.name, stage: stageMap[x.o.pipelineStageId] || 'Unknown', days: x.days })),
    missingBrief: missingBrief.slice(0, 15),
    revenue,
    revTotal: total,
    hot: hot.slice(0, 15).map(x => ({ name: x.o.contact?.name || x.o.name, stage: stageMap[x.o.pipelineStageId] || 'Unknown', lead: x.lead, alignment: x.align, lastContactDays: x.lastContactDays }))
  };
  console.log(JSON.stringify(out, null, 2));
})();

